def get_sum(a, b):
    mask = 0xFFFFFFFF
    a &= mask
    b &= mask
    while b:
        carry = (a & b) << 1
        a = (a ^ b) & mask
        b = carry & mask
    if a <= 0x7FFFFFFF:
        return a
    return ~(a ^ mask)
